// Simple local auth — replace with your DB lookup
const { email, password } = msg.payload;

// Demo: accept any valid email + password >= 6 chars
if (!email || !password || password.length < 6) {
    msg.statusCode = 401;
    msg.payload = { message: 'Invalid credentials' };
    return msg;
}

// Generate a simple JWT-like token (use jsonwebtoken in production)
const token = Buffer.from(JSON.stringify({
    sub: email,
    iat: Date.now(),
    exp: Date.now() + 86400000
})).toString('base64');

const user = {
    id: 'local-' + Buffer.from(email).toString('base64').slice(0,8),
    name: email.split('@')[0],
    email: email,
    provider: 'local',
    avatar: 'https://ui-avatars.com/api/?name=' + encodeURIComponent(email.split('@')[0]) + '&background=00e5ff&color=060810&bold=true',
    role: 'user',
    loginAt: new Date().toISOString()
};

msg.statusCode = 200;
msg.payload = { token, user };
return msg;

