// Configure your Google Client ID in environment variables
const clientId = env.get('GOOGLE_CLIENT_ID') || 'YOUR_GOOGLE_CLIENT_ID';
const redirectUri = encodeURIComponent('http://localhost:1880/auth/google/callback');
const scope = encodeURIComponent('openid email profile');

msg.statusCode = 302;
msg.headers = {
    Location: `https://accounts.google.com/o/oauth2/v2/auth?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=code&scope=${scope}`
};
msg.payload = '';
return msg;

const appId = env.get('FACEBOOK_APP_ID') || 'YOUR_FACEBOOK_APP_ID';
const redirectUri = encodeURIComponent('http://localhost:1880/auth/facebook/callback');
const scope = encodeURIComponent('email,public_profile');

msg.statusCode = 302;
msg.headers = {
    Location: `https://www.facebook.com/v18.0/dialog/oauth?client_id=${appId}&redirect_uri=${redirectUri}&scope=${scope}&response_type=code`
};
msg.payload = '';
return msg;
